pub fn load_agent_eval_tasks(path: &Path) -> anyhow::Result<Vec<AgentEvalTask>> {
    let bytes = std::fs::read(path)?;
    let mut tasks: Vec<AgentEvalTask> = serde_json::from_slice(&bytes)?;
